#include <stdio.h>
#include <stdbool.h>
int main(){
    int T,a,b,op;
    if(scanf("%d",&T)!=1) return 0;
    bool running=true;
    while(T-- && running){
        if(scanf("%d %d %d",&a,&b,&op)!=3) break;
        switch(op){
            case 1: printf("Result: %d\n",a+b); break;
            case 2: printf("Result: %d\n",a-b); break;
            case 3: printf("Result: %d\n",a*b); break;
            case 4: if(b==0) printf("Error: Division by zero.\n"); else printf("Result: %d\n",a/b); break;
            case 5: printf("Result: Exit\n"); running=false; break;
            default: printf("Error: Operation does not exist.\n");
        }
    }
    return 0;
}

