code.Java:
import java.io.*;
import java.util.*;
public class Main{
    public static void main(String[] args) throws IOException{
        BufferedReader br=new BufferedReader(new InputStreamReader(System.in));
        String line=br.readLine();
        if(line==null||line.isEmpty()) return;
        int T=Integer.parseInt(line.trim());
        StringBuilder sb=new StringBuilder();
        boolean running=true;
        for(int i=0;i<T && running;i++){
            line=br.readLine();
            if(line==null) break;
            StringTokenizer st=new StringTokenizer(line);
            int a=Integer.parseInt(st.nextToken());
            int b=Integer.parseInt(st.nextToken());
            int op=Integer.parseInt(st.nextToken());
            switch(op){
                case 1: sb.append("Result: ").append(a+b).append('\n'); break;
                case 2: sb.append("Result: ").append(a-b).append('\n'); break;
                case 3: sb.append("Result: ").append(a*b).append('\n'); break;
                case 4: if(b==0) sb.append("Error: Division by zero.").append('\n'); else sb.append("Result: ").append(a/b).append('\n'); break;
                case 5: sb.append("Result: Exit").append('\n'); running=false; break;
                default: sb.append("Error: Operation does not exist.").append('\n');
            }
        }
        System.out.print(sb.toString());
    }
}

