import sys
def main():
    data=sys.stdin.read().strip().splitlines()
    if not data:
        return
    T=int(data[0])
    out=[]
    running=True
    idx=1
    while idx<=T and running and idx<len(data):
        a,b,op=map(int,data[idx].split())
        idx+=1
        if op==1:
            out.append(f"Result: {a+b}")
        elif op==2:
            out.append(f"Result: {a-b}")
        elif op==3:
            out.append(f"Result: {a*b}")
        elif op==4:
            if b==0:
                out.append("Error: Division by zero.")
            else:
                out.append(f"Result: {a//b}")
        elif op==5:
            out.append("Result: Exit")
            running=False
        else:
            out.append("Error: Operation does not exist.")
    sys.stdout.write("\n".join(out))
if __name__=="__main__":
    main()

